@php
    $formatSeconds = function ($seconds) { $seconds = max(0, (int) $seconds); return intdiv($seconds, 3600).'h '.str_pad((string) intdiv($seconds % 3600, 60), 2, '0', STR_PAD_LEFT).'m'; };
    $formatDate = fn ($date) => \Carbon\Carbon::parse($date, $corporateTimezone)->locale('es')->isoFormat('D MMM YYYY');
    $today = now($corporateTimezone)->toDateString();
    $quickRanges = [['Hoy', $today, $today], ['7 días', now($corporateTimezone)->subDays(6)->toDateString(), $today], ['30 días', now($corporateTimezone)->subDays(29)->toDateString(), $today]];
    $totals = (object) ['active' => $rows->sum('active_seconds'), 'idle' => $rows->sum('idle_seconds'), 'late' => $rows->where('late_minutes', '>', 0)->count(), 'early' => $rows->where('early_minutes', '>', 0)->count(), 'blocked' => $rows->sum('blocked_attempts')];
    $onTime = $rows->filter(fn ($row) => !$row->late_minutes && !$row->early_minutes)->count();
    $compliance = $rows->count() ? (int) round(($onTime / $rows->count()) * 100) : 0;
    $groups = $rows->groupBy('employee_id')->map(function ($items) {
        $first = $items->first();
        $onTimeDays = $items->filter(fn ($row) => !$row->late_minutes && !$row->early_minutes)->count();
        return (object) ['id' => $first->employee_id, 'name' => $first->employee_name, 'department' => $first->department, 'rows' => $items->sortByDesc('date'), 'active' => $items->sum('active_seconds'), 'idle' => $items->sum('idle_seconds'), 'locked' => $items->sum('locked_seconds'), 'blocked' => $items->sum('blocked_attempts'), 'late' => $items->where('late_minutes', '>', 0)->count(), 'early' => $items->where('early_minutes', '>', 0)->count(), 'compliance' => $items->count() ? (int) round(($onTimeDays / $items->count()) * 100) : 0];
    })->sortBy('name');
@endphp
